sql:
SELECT COUNT(*) AS exam_count
FROM exam_room_schedules
WHERE exam_room_id = 1 AND scheduled_date = '2023-07-04';

SELECT COUNT(student_id) AS number_of_students
FROM exam_registrations
WHERE exam_id = 1;

SELECT status
FROM exam_attendance
WHERE exam_id = 0;

SELECT room_name
FROM exam_rooms
WHERE room_type = 'Lecture Hall';

SELECT COUNT(*) AS absent_students
FROM exam_attendance
WHERE exam_id = 0 AND attendance_date = '2023-07-05' AND status = 'Absent';

SELECT room_name, capacity
FROM exam_rooms
ORDER BY capacity DESC;

SELECT exam_type_name
FROM exam_types
WHERE exam_type_category = 'Theory';

SELECT material_type, file_path
FROM exam_materials
WHERE material_status = 'Approved';

